INSERT INTO contract_templates (contract_type, jurisdiction, version, title, preamble, recitals, clauses, signature_block, placeholders, is_active, metadata) VALUES (
  'nda_one_way',
  'us_new_york',
  1,
  'One-Way Non-Disclosure Agreement (New York)',
  'This Non-Disclosure Agreement (the "Agreement") is entered into as of {{effective_date}} (the "Effective Date") by and between (i) {{party_a_company}}, with a mailing address of {{party_a_address}} (the "Disclosing Party" or "{{party_a_name}}"), and (ii) {{party_b_company}}, with a mailing address of {{party_b_address}} (the "Receiving Party" or "{{party_b_name}}").',
  'WHEREAS, the Disclosing Party possesses certain confidential and proprietary information that it wishes to disclose to the Receiving Party in connection with {{purpose}} (the "Purpose");

WHEREAS, the Receiving Party wishes to receive such information and agrees to protect its confidentiality in accordance with the terms of this Agreement and applicable New York law;

NOW, THEREFORE, in consideration of the mutual promises and covenants contained herein, the parties agree as follows:',
  '[{"id":"definitions","title":"1. DEFINITIONS","content":"1.1 \"Confidential Information\" means any non-public information disclosed by or on behalf of the Disclosing Party to the Receiving Party, whether disclosed before or after the Effective Date, and whether disclosed in writing, orally, visually, electronically, or in any other form, that (a) is designated as confidential or proprietary, or (b) reasonably should be understood to be confidential given the nature of the information or the circumstances of disclosure.\n\n1.2 Confidential Information includes, without limitation: business, financial, and product plans; customer and supplier information; pricing; forecasts; marketing information; technical data; inventions; algorithms; designs; specifications; software; research and development; know-how; processes; and any information derived from Confidential Information.\n\n1.3 \"Trade Secret\" means information that qualifies as a trade secret under New York common law and the federal Defend Trade Secrets Act. Trade Secrets are included within Confidential Information.\n\n1.4 \"Representatives\" means the Receiving Party''s directors, officers, employees, agents, professional advisors, contractors, and consultants who have a need to know the Confidential Information for the Purpose.","type":"standard","order":1},{"id":"confidentiality_obligations","title":"2. CONFIDENTIALITY OBLIGATIONS","content":"2.1 Use Restriction. The Receiving Party shall use the Confidential Information solely for the Purpose and for no other purpose without the Disclosing Party''s prior written consent.\n\n2.2 Non-Disclosure. The Receiving Party shall not disclose the Confidential Information to any person or entity except to its Representatives who have a need to know for the Purpose.\n\n2.3 Standard of Care. The Receiving Party shall protect the Confidential Information using at least the same degree of care used to protect its own confidential information, but no less than reasonable care.\n\n2.4 Security Measures. The Receiving Party shall implement reasonable administrative, technical, and physical safeguards to protect the Confidential Information.\n\n2.5 Compelled Disclosure. If required by law or legal process to disclose Confidential Information, the Receiving Party shall (to the extent legally permitted) provide prompt written notice and cooperate in seeking a protective order.\n\n2.6 Trade Secret Protections. Nothing in this Agreement limits rights or remedies available under New York common law or the federal Defend Trade Secrets Act.","type":"standard","order":2},{"id":"exclusions","title":"3. EXCLUSIONS FROM CONFIDENTIAL INFORMATION","content":"3.1 Exclusions. Confidential Information does not include information that the Receiving Party can demonstrate:\n\n(a) is or becomes publicly available through no breach of this Agreement;\n\n(b) was lawfully known to the Receiving Party before disclosure;\n\n(c) is lawfully received from a third party without confidentiality restrictions;\n\n(d) is independently developed without use of Confidential Information; or\n\n(e) is approved for release in writing by the Disclosing Party.","type":"standard","order":3},{"id":"term_and_duration","title":"4. TERM AND DURATION","content":"4.1 Term. This Agreement begins on the Effective Date and continues until the earlier of (a) {{expiration_date}}, or (b) termination by either party upon {{notice_period}} days'' written notice.\n\n4.2 Survival. Confidentiality obligations survive termination for {{confidentiality_period}} years from disclosure of the applicable Confidential Information.\n\n4.3 Trade Secrets. Obligations regarding Trade Secrets continue for so long as such information remains a Trade Secret under applicable law.","type":"standard","order":4},{"id":"return_of_information","title":"5. RETURN OR DESTRUCTION OF INFORMATION","content":"5.1 Return/Destruction. Upon request, the Receiving Party shall promptly return or destroy all Confidential Information and certify such return or destruction in writing.\n\n5.2 Archival Copies. The Receiving Party may retain copies required by law or bona fide document retention policies, subject to ongoing confidentiality obligations.","type":"standard","order":5},{"id":"remedies","title":"6. REMEDIES","content":"6.1 Injunctive Relief. The Receiving Party acknowledges that unauthorized disclosure may cause irreparable harm. The Disclosing Party is entitled to seek injunctive relief without proving actual damages or posting bond (to the extent permitted by law).\n\n6.2 Attorneys'' Fees. The prevailing party in any enforcement action may recover reasonable attorneys'' fees to the extent permitted by New York law.\n\n6.3 Statutory Rights. This Agreement does not limit rights under New York common law or the federal Defend Trade Secrets Act.","type":"negotiable","order":6},{"id":"governing_law","title":"7. GOVERNING LAW; VENUE","content":"7.1 Governing Law. This Agreement shall be governed by the laws of the State of New York, without regard to conflict of laws principles.\n\n7.2 Venue. The parties consent to exclusive jurisdiction of the state and federal courts in {{venue_county}} County, New York.\n\n7.3 Injunctive Relief. A party may seek injunctive relief in any court of competent jurisdiction.","type":"standard","order":7},{"id":"general_provisions","title":"8. GENERAL PROVISIONS","content":"8.1 Notices. Notices must be in writing and delivered personally, by overnight courier, certified mail, or email with confirmation.\n\n8.2 No License. No intellectual property rights are granted except the limited right to use Confidential Information for the Purpose.\n\n8.3 No Partnership/Agency. Nothing creates any partnership, joint venture, or agency relationship.\n\n8.4 Defend Trade Secrets Act Notice. Pursuant to 18 U.S.C. § 1833(b), an individual shall not be held liable for disclosure of a trade secret made in confidence to a government official or attorney for reporting or investigating suspected violations of law, or in a sealed court filing.\n\n8.5 Severability. Invalid provisions shall be enforced to the maximum extent permitted by law.\n\n8.6 Waiver. Waivers must be in writing.\n\n8.7 Assignment. Neither party may assign without consent, except to a successor in a merger or acquisition.\n\n8.8 Entire Agreement. This Agreement is the entire agreement and supersedes prior understandings. Amendments must be in writing signed by both parties.\n\n8.9 Electronic Signatures. Electronic signatures are enforceable under the New York Electronic Signatures and Records Act (ESRA) and the federal ESIGN Act.","type":"standard","order":8}]'::jsonb,
  'IN WITNESS WHEREOF, the parties have executed this Agreement as of {{signature_date}}.

DISCLOSING PARTY:
{{party_a_company}}

By (Signature): ________________________________
Printed Name: {{party_a_name}}
Title: {{party_a_title}}
Email: {{party_a_email}}
Address: {{party_a_address}}
Date: {{signature_date}}

RECEIVING PARTY:
{{party_b_company}}

By (Signature): ________________________________
Printed Name: {{party_b_name}}
Title: {{party_b_title}}
Email: {{party_b_email}}
Address: {{party_b_address}}
Date: {{signature_date}}',
  '[{"id":"party_a_email","token":"{{party_a_email}}","label":"Your Email","description":"Email address of the disclosing party","category":"party_a","type":"email","required":true,"autofillKey":"email"},{"id":"party_a_name","token":"{{party_a_name}}","label":"Your Name","description":"Full legal name","category":"party_a","type":"text","required":true,"autofillKey":"name"},{"id":"party_a_address","token":"{{party_a_address}}","label":"Your Address","description":"Business or mailing address","category":"party_a","type":"textarea","required":false,"autofillKey":"address"},{"id":"party_a_company","token":"{{party_a_company}}","label":"Your Company","description":"Company name","category":"party_a","type":"text","required":false,"autofillKey":"company_name"},{"id":"party_a_title","token":"{{party_a_title}}","label":"Your Title","description":"Job title","category":"party_a","type":"text","required":false,"autofillKey":"job_title"},{"id":"party_b_email","token":"{{party_b_email}}","label":"Receiving Party Email","description":"Email address","category":"party_b","type":"email","required":true},{"id":"party_b_name","token":"{{party_b_name}}","label":"Receiving Party Name","description":"Full legal name","category":"party_b","type":"text","required":true},{"id":"party_b_address","token":"{{party_b_address}}","label":"Receiving Party Address","description":"Business or mailing address","category":"party_b","type":"textarea","required":false},{"id":"party_b_company","token":"{{party_b_company}}","label":"Receiving Party Company","description":"Company name","category":"party_b","type":"text","required":false},{"id":"party_b_title","token":"{{party_b_title}}","label":"Receiving Party Title","description":"Job title","category":"party_b","type":"text","required":false},{"id":"effective_date","token":"{{effective_date}}","label":"Effective Date","description":"When the agreement becomes effective","category":"dates","type":"date","required":true},{"id":"expiration_date","token":"{{expiration_date}}","label":"Expiration Date","description":"When the agreement ends","category":"dates","type":"date","required":false},{"id":"signature_date","token":"{{signature_date}}","label":"Signature Date","description":"Date of signing","category":"dates","type":"date","required":false},{"id":"venue_county","token":"{{venue_county}}","label":"Venue County","description":"New York county for legal venue","category":"terms","type":"text","required":true},{"id":"confidentiality_period","token":"{{confidentiality_period}}","label":"Confidentiality Period","description":"Years of confidentiality obligation","category":"terms","type":"number","required":false},{"id":"notice_period","token":"{{notice_period}}","label":"Notice Period","description":"Days notice for termination","category":"terms","type":"number","required":false},{"id":"purpose","token":"{{purpose}}","label":"Purpose","description":"Purpose of the disclosure","category":"terms","type":"textarea","required":false}]'::jsonb,
  true,
